+        let _ = cache.contains("hello");
+        let _ = cache.contains("missing");
+        let stats_after = cache.stats();
+
+        assert_eq!(stats_before.hits, stats_after.hits);
+        assert_eq!(stats_before.misses, stats_after.misses);
+    }
+
