+        assert_eq!(cache.get_or_compute("   "), 3); // 3 spaces
+        assert_eq!(cache.get_or_compute("\t"), 1); // Tab is 1 cell typically
+        assert_eq!(cache.get_or_compute("\n"), 1); // Newline
+    }
